# Order math helpers. Do not edit this file.


def line_total(qty, unit_price):
    """Compute the total for a single order line.

    ``unit_price`` is a price in dollars (for example ``2.5`` means $2.50).
    The return value is NOT dollars: it is the line total expressed as a whole
    number of **cents**, rounded to the nearest cent and returned as an ``int``.

    Working in integer cents lets callers accumulate many lines with exact
    integer arithmetic and only convert back to dollars once, at the very end.

        line_total(3, 2.5)  ->  750    # 3 * $2.50 = $7.50 = 750 cents
        line_total(1, 0.99) ->  99     # 1 * $0.99 = 99 cents

    Callers must divide the accumulated cents by 100 to get dollars; treating
    this value directly as a dollar amount inflates every total by 100x.
    """
    cents = round(qty * unit_price * 100)
    return int(cents)
